$(document).ready(function(){AOS.init({disable:"mobile"}),$.fn.randomize=function(n){return(n?$(this).find(n):$(this).children()).parent().each(function(){$(this).children(n).sort(function(i,e){if($(e).index()!==$(this).children(n).length-1)return Math.round(Math.random())-.5}.bind(this)).detach().appendTo(this)}),this},$(".quote-carousel").randomize().slick({autoplay:!0,autoplaySpeed:4e3,arrows:!1,fade:!0,pauseOnFocus:!1,pauseOnHover:!1}),$(".carousel").slick(),$(".sticky").stick_in_parent()});